def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                factor = np.sin(ratio * a * np.pi) + 1.5
                temp = np.exp(-ratio * a**1.1) * (a ** 3.1) / factor
                if a % 2 == 0:
                    temp *= 0.92
                else:
                    temp *= 1.07
                score += temp
            if (capacity % 4 == 0) or ((item * 7) % 2 == 1):
                score *= 0.85
            if score > 12:
                score /= (1 + np.log1p(capacity))
        elif 0.05 <= ratio < 0.25:
            product = 1
            for n in range(1, int(capacity) + 3):
                product *= (ratio + n / (n + 2) + np.cos(n * ratio))
                if product > 5e6:
                    product = np.log1p(product)
                    break
            mod_val = int(product) % 500
            score += np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 8 == 0) and ((item * 5) % 4 == 0):
                score += 5.5
            else:
                score -= 1.1
            extra_sum = 0
            for x in range(1, 8):
                val = ((ratio * x**2.3) % 1) * (x ** 2.3)
                if x % 2 == 0:
                    val *= 1.2
                else:
                    val *= 0.8
                extra_sum += val
            score += extra_sum / 7
        elif 0.25 <= ratio <= 0.55:
            for m in range(1, 10):
                power = ratio ** (m + 3)
                weight = m ** 3.0
                denom = ((m + 3) ** 1.1)
                increment = power * weight / denom
                score += increment
            remainder = capacity - item
            if remainder < 4:
                score += 15 + remainder * 0.7
                if int(capacity) % 5 == 0:
                    score += np.sqrt(remainder) * 2
            else:
                score -= remainder * 1.1
            if score < -10:
                score = abs(score) * 0.25 + 3
            if int(capacity) % 9 == 0:
                score *= 1.3
            if score > 20:
                score /= 3.5
        elif 0.55 < ratio <= 0.85:
            penalty_base = 0
            for p in range(1, 15):
                val = ((ratio - 0.55) ** p) * (p ** 1.8) * np.sin(p * ratio)
                penalty_base += val
                if penalty_base > 90:
                    penalty_base = np.log1p(abs(penalty_base))
                    break
            score = penalty_base * 15
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 6) % 9 == 0) and (int(item * 7) % 13 == 0):
                score -= 8
            if score < 0:
                score *= -1.8
                score += 7
            if score > 130:
                score = 130
        elif 0.85 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 13):
                term = ((diff) ** q) * (q ** 3.0) / (q + 2)
                if q % 2 == 0:
                    term *= 0.95
                else:
                    term *= 1.1
                penalty_ext += term
                if penalty_ext > 1400:
                    penalty_ext = np.log1p(penalty_ext)
                    break
            score = penalty_ext * 22
            if capacity < item * 1.4:
                score += 25
            if (int(capacity * 4) % 6 == 0) and (int(item * 10) % 5 == 0):
                score -= 9
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.3)
            if score < 0:
                score = abs(score) * 0.55
            if score > 1400:
                score = 1400
        else:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 15000:
                    term = np.sqrt(term) * 1.1
                super_penalty += term
                if super_penalty > 35000:
                    super_penalty = np.log1p(super_penalty)
                    break
            score = super_penalty * 28
            if capacity < item * 2.2:
                score += 30
            if (int(capacity * 15) % 5 == 0) and (int(item * 20) % 7 == 0):
                score -= 13
            for w in range(2, 10):
                score += ((diff / w) % 1) * (w * 2.7)
            if score < 0:
                score = abs(score) * 0.7 + 6
            if score > 2500:
                score = 2500
        if capacity > 250:
            score /= (np.log1p(capacity) + 1.5)
            if ratio > 0.5 and ratio < 1.0:
                boost = np.log1p(score + capacity) / (ratio * 20)
                score += boost
        elif capacity < 4:
            score *= 2.8
            if score < 0:
                score *= -1
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 1
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val * 0.8
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 1
    return priorities
